const outputs = $input.first().json.output;
var programJson;
outputs.map((output) => {
  if (output.type === "message" && output.content) {
    programJson = output.content[0].text;
  }
});


return programJson;

const programming = $input.first().json.programming;

console.log("programming", programming);

const slugify = (str) => str.toLowerCase()
  .replace(/[\u2018\u2019']/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const programSlug = programming.slug || slugify(programming.name);

// create the index.md markdown file
const createIndexPage = () => {
  return `---\ntitle: "${programming.name}"\nmonthSlug: "${programSlug}"\nstartDate: "${programming.id}"\nfeatured: true\n---\n  ## Program Overview \n  ${programming.description}\n`;
}

const createDayItem = (day, index) => {
  return `---\ntitle: "${day.name}"\ndayNumber: ${index}\n---\n${day.description}\n${day.programming}\n`;
}

const workoutsList = programming.weeks[0].workouts;
var dayListObject = workoutsList.map((workout, index) => {
  return {
    slug: workout.slug || slugify(workout.name),
    content: createDayItem(workout, index)
  };
});

const indexPage = createIndexPage();
return {
  id: programSlug,
  index: indexPage,
  days: dayListObject
};

const existingFolders = $('List Existing Programs').all().map(item => item.json.name)

const baseSlug = $('Code in JavaScript1').first().json.id;
const data = $('Code in JavaScript1').first().json;

let slug = baseSlug;
let suffix = 2;
while (existingFolders.includes(slug)) {
  slug = `${baseSlug}-${suffix}`;
  suffix++;
}

// Pass through all data with the resolved slug
return {
  ...data,
  id: slug
};
